package com.veetu.vadagai.payment;import com.veetu.vadagai.payment.PaymentDtos.*;import com.veetu.vadagai.property.PropertyRepository;import com.veetu.vadagai.user.CurrentUserService;import lombok.RequiredArgsConstructor;import org.springframework.data.domain.*;import org.springframework.stereotype.Service;import org.springframework.transaction.annotation.Transactional;import java.math.BigDecimal;import java.util.*;
@Service @RequiredArgsConstructor public class PaymentService{private final PaymentRepository payments;private final PropertyRepository properties;private final CurrentUserService current;@Transactional public PaymentResponse create(PaymentRequest r){var p=properties.findById(r.propertyId()).orElseThrow();var pay=payments.save(Payment.builder().payer(current.get()).property(p).type(r.type()).status(PaymentStatus.CREATED).amount(r.amount()).lateFee(BigDecimal.ZERO).dueDate(r.dueDate()).gatewayOrderId("order_"+UUID.randomUUID().toString().replace("-","")).build());return map(pay);}@Transactional public PaymentResponse webhook(RazorpayWebhook w){var pay=payments.findAll().stream().filter(p->w.orderId().equals(p.getGatewayOrderId())).findFirst().orElseThrow();pay.setGatewayPaymentId(w.paymentId());pay.setStatus("captured".equalsIgnoreCase(w.status())?PaymentStatus.SUCCESS:PaymentStatus.FAILED);pay.setReceiptUrl("/api/v1/invoices/"+pay.getId()+"/pdf");return map(pay);}public Page<PaymentResponse> mine(Pageable p){return payments.findByPayerIdAndDeletedFalse(current.get().getId(),p).map(this::map);}PaymentResponse map(Payment p){return new PaymentResponse(p.getId(),p.getType(),p.getStatus(),p.getAmount(),p.getDueDate(),p.getGatewayOrderId(),p.getReceiptUrl());}}
